func TestArrayStdinMutationCommandsAcceptJSONArray(t *testing.T) {
	const dnsBody = `[{"type":"A","name":"@","data":"192.0.2.10","ttl":600}]`
	const expiryListingsBody = `[{"domain":"example.com","expiresAt":"2026-12-31T00:00:00Z"}]`

	cases := []struct {
		name  string
		args  []string
		stdin string
	}{
		{
			name:  "dns replace all",
			args:  []string{"domains", "records", "replace", "example.com", "--stdin", "--json"},
			stdin: dnsBody,
		},
		{
			name:  "dns replace type",
			args:  []string{"domains", "records", "replace-type", "example.com", "--type", "A", "--stdin", "--json"},
			stdin: dnsBody,
		},
		{
			name:  "dns replace type name",
			args:  []string{"domains", "records", "replace-type-name", "example.com", "@", "--type", "A", "--stdin", "--json"},
			stdin: dnsBody,
		},
		{
			name:  "dns add",
			args:  []string{"domains", "records", "add", "example.com", "--stdin", "--json"},
			stdin: dnsBody,
		},
		{
			name:  "aftermarket add expiry listings",
			args:  []string{"aftermarket", "add-expiry-listings", "--stdin", "--json"},
			stdin: expiryListingsBody,
		},
	}

	for _, tc := range cases {
		tc := tc
		t.Run(tc.name, func(t *testing.T) {
			t.Setenv("PRINTING_PRESS_VERIFY", "1")
			t.Setenv("PRINTING_PRESS_VERIFY_LIVE_HTTP", "")
			t.Setenv("GODADDY_ALLOW_WRITES", "")
			restoreStdin := replaceStdin(t, tc.stdin)
			defer restoreStdin()

			cmd := RootCmd()
			var out bytes.Buffer
			cmd.SetOut(&out)
			cmd.SetErr(io.Discard)
			cmd.SetArgs(tc.args)

			if err := cmd.Execute(); err != nil {
				t.Fatalf("Execute(%v) returned error: %v", tc.args, err)
			}
			var envelope map[string]any
			if err := json.Unmarshal(out.Bytes(), &envelope); err != nil {
				t.Fatalf("Execute(%v) output is not JSON: %v; raw=%q", tc.args, err, out.String())
			}
			if got, _ := envelope["verify_noop"].(bool); !got {
				t.Fatalf("Execute(%v) verify_noop = %v, want true; envelope=%v", tc.args, envelope["verify_noop"], envelope)
			}
			data, _ := envelope["data"].(map[string]any)
			if got, _ := data["__pp_verify_synthetic__"].(bool); !got {
				t.Fatalf("Execute(%v) data.__pp_verify_synthetic__ = %v, want true; envelope=%v", tc.args, data["__pp_verify_synthetic__"], envelope)
			}
		})
	}
}

func TestAftermarketAddExpiryListingsRequiresStdin(t *testing.T) {
	t.Setenv("PRINTING_PRESS_VERIFY", "1")
	t.Setenv("PRINTING_PRESS_VERIFY_LIVE_HTTP", "")

	cmd := RootCmd()
	cmd.SetOut(io.Discard)
	cmd.SetErr(io.Discard)
	cmd.SetArgs([]string{"aftermarket", "add-expiry-listings", "--json"})

	err := cmd.Execute()
	if err == nil {
		t.Fatal("Execute returned nil error, want --stdin usage error")
	}
	if !strings.Contains(err.Error(), "--stdin is required") {
		t.Fatalf("error = %v, want --stdin requirement", err)
	}
	if got := ExitCode(err); got != 2 {
		t.Fatalf("ExitCode = %d, want 2 for usage error", got)
	}
}

